from collections import deque, defaultdict

def topological_sort(graph):
    # Step 1: Compute in-degree (number of incoming dependencies) for each node
    in_degree = {node: 0 for node in graph}
    for nodes in graph.values():
        for node in nodes:
            in_degree[node] += 1

    # Step 2: Initialize a queue with all nodes that have no incoming dependencies
    zero_in_degree_queue = deque([node for node, degree in in_degree.items() if degree == 0])

    top_order = []

    # Step 3: Process nodes and reduce the in-degree of their neighbors by one
    while zero_in_degree_queue:
        node = zero_in_degree_queue.popleft()
        top_order.append(node)

        for dependent_node in graph.get(node, []):
            in_degree[dependent_node] -= 1
            if in_degree[dependent_node] == 0:
                zero_in_degree_queue.append(dependent_node)

    # Step 4: Check for cycles and return the result or raise an error if a cycle is detected
    if len(top_order) != len(graph):
        raise ValueError("Graph has at least one cycle, topological sorting is not possible.")

    return top_order

# Example usage:
graph = {
    'A': ['B', 'C'],
    'B': ['D'],
    'C': ['D'],
    'D': []
}

print(topological_sort(graph))  # Output: ['A', 'C', 'B', 'D']
```

This function computes a topological ordering of nodes in the graph, ensuring that all dependencies are respected. It handles cycles by raising an error if detected during the process.
